// ─── SURVEY VIEW ─────────────────────────────────────────────────────────────
function SurveyView({ sections, onSubmit, onHome }) {
  const [step, setStep] = useState(0);
  const [sectionAnswers, setSectionAnswers] = useState({});
  const [cur, setCur] = useState({});
  const total = sections.length;
  const section = sections[step - 1];
  const isDone = step > total;

  const setAns = (qid, val) => setCur(c => ({ ...c, [qid]: val }));
  const toggleMulti = (qid, opt) => {
    const prev = cur[qid] || [];
    setCur(c => ({ ...c, [qid]: prev.includes(opt) ? prev.filter(x => x !== opt) : [...prev, opt] }));
  };

  const mergeAnswers = () => {
    const merged = { ...sectionAnswers };
    if (section) {
      section.questions.forEach(q => {
        if (cur[q.id] !== undefined) merged[`${section.id}_${q.id}`] = cur[q.id];
      });
    }
    return merged;
  };

  const handleNext = () => {
    setSectionAnswers(mergeAnswers());
    setCur({});
    setStep(s => s + 1);
  };

  const handleFinalSubmit = () => {
    onSubmit(mergeAnswers());
    setCur({});
    setSectionAnswers({});
    setStep(s => s + 1);
  };

  const progress = step === 0 ? 0 : Math.round((step / total) * 100);

  return (
    <div style={{ minHeight: "100vh", background: DARK, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 20, fontFamily: "'DM Sans',sans-serif" }}>
      <style>{globalCSS}</style>

      <div style={{ marginBottom: 24 }}>
        <img src={LOGO_B64} alt="PADFIT" style={{ height: 48, objectFit: "contain", filter: "drop-shadow(0 0 10px rgba(57,255,20,0.4))", cursor: "pointer" }} onClick={onHome} />
      </div>

      <div style={{ width: "100%", maxWidth: 480, background: CARD, borderRadius: 20, border: `1px solid ${BORDER}`, overflow: "hidden", boxShadow: "0 24px 80px rgba(0,0,0,0.7)" }}>
        {step > 0 && !isDone && (
          <div style={{ height: 3, background: "#1a1a1a" }}>
            <div style={{ height: "100%", width: `${progress}%`, background: "linear-gradient(90deg,#39FF14,#7fff00)", transition: "width 0.4s ease" }} />
          </div>
        )}

        <div style={{ padding: "28px 24px" }}>
          {/* INTRO */}
          {step === 0 && (
            <div style={{ textAlign: "center" }}>
              <div style={{ fontSize: "2.8rem", marginBottom: 12 }}>🏆</div>
              <h1 style={{ color: "#fff", fontFamily: "'Barlow Condensed',sans-serif", fontSize: "2.2rem", letterSpacing: "0.05em", marginBottom: 8, lineHeight: 1.1 }}>
                CUÉNTANOS TU<br /><span style={{ color: GREEN }}>EXPERIENCIA</span>
              </h1>
              <p style={{ color: MUTED, fontSize: "0.88rem", lineHeight: 1.7, marginBottom: 20 }}>
                Tu opinión nos ayuda a mejorar cada área de PADFIT. Son solo {total} secciones rápidas.
              </p>
              <div style={{ display: "flex", gap: 8, justifyContent: "center", flexWrap: "wrap", marginBottom: 24 }}>
                {["⚡ 3 min", "🔒 Anónima", "📱 Fácil"].map(t => (
                  <span key={t} style={{ padding: "4px 12px", borderRadius: 20, border: `1px solid ${BORDER}`, color: MUTED, fontSize: "0.72rem", fontFamily: "monospace" }}>{t}</span>
                ))}
              </div>
              <button onClick={() => setStep(1)} className="nxt" style={{ width: "100%", padding: "14px", borderRadius: 12, border: "none", background: `linear-gradient(135deg,${GREEN},#7fff00)`, color: DARK, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1.1rem", fontWeight: 700, cursor: "pointer", letterSpacing: "0.1em", transition: "all 0.2s" }}>
                COMENZAR →
              </button>
            </div>
          )}

          {/* QUESTIONS */}
          {step > 0 && !isDone && section && (
            <div>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
                <span style={{ color: MUTED, fontFamily: "monospace", fontSize: "0.7rem" }}>{step}/{total}</span>
                <span style={{ color: GREEN, fontFamily: "monospace", fontSize: "0.7rem" }}>{progress}%</span>
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 18, padding: "10px 14px", borderRadius: 10, background: "rgba(57,255,20,0.05)", border: "1px solid rgba(57,255,20,0.15)" }}>
                <span style={{ fontSize: "1.6rem" }}>{section.icon}</span>
                <span style={{ color: GREEN, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1.2rem", fontWeight: 700, letterSpacing: "0.08em" }}>{section.label.toUpperCase()}</span>
              </div>

              {section.questions.map((q, qi) => (
                <div key={q.id} style={{ marginBottom: 18 }}>
                  <p style={{ color: TEXT, fontSize: "0.9rem", lineHeight: 1.5, marginBottom: 10, fontWeight: 500 }}>
                    <span style={{ color: GREEN, fontFamily: "monospace", fontSize: "0.72rem", marginRight: 8 }}>{qi + 1}.</span>
                    {q.text}
                  </p>
                  {q.type === "rating" && <Stars value={cur[q.id] || 0} onChange={v => setAns(q.id, v)} />}
                  {q.type === "nps" && <NPS value={cur[q.id]} onChange={v => setAns(q.id, v)} />}
                  {q.type === "single" && (
                    <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                      {q.options.map(opt => {
                        const sel = cur[q.id] === opt;
                        return (
                          <button key={opt} className="opt" onClick={() => setAns(q.id, opt)} style={{ padding: "10px 14px", borderRadius: 8, textAlign: "left", border: sel ? `1.5px solid ${GREEN}` : `1.5px solid ${BORDER}`, background: sel ? "rgba(57,255,20,0.08)" : "#0e0e0e", color: sel ? GREEN : MUTED, fontSize: "0.85rem", cursor: "pointer", transition: "all 0.15s" }}>
                            {sel ? "◉" : "○"} {opt}
                          </button>
                        );
                      })}
                    </div>
                  )}
                  {q.type === "multi" && (
                    <div style={{ display: "flex", flexWrap: "wrap", gap: 7 }}>
                      {q.options.map(opt => {
                        const sel = (cur[q.id] || []).includes(opt);
                        return (
                          <button key={opt} className="opt" onClick={() => toggleMulti(q.id, opt)} style={{ padding: "7px 14px", borderRadius: 30, border: sel ? `1.5px solid ${GREEN}` : `1.5px solid ${BORDER}`, background: sel ? "rgba(57,255,20,0.1)" : "transparent", color: sel ? GREEN : "#888", fontSize: "0.8rem", cursor: "pointer", transition: "all 0.15s" }}>
                            {opt}
                          </button>
                        );
                      })}
                    </div>
                  )}
                  {q.type === "open" && (
                    <textarea value={cur[q.id] || ""} onChange={e => setAns(q.id, e.target.value)} placeholder="Tu comentario... (opcional)"
                      style={{ width: "100%", minHeight: 80, padding: "12px", background: "#0e0e0e", border: `1.5px solid ${BORDER}`, borderRadius: 8, color: TEXT, fontSize: "0.85rem", fontFamily: "'DM Sans',sans-serif", resize: "vertical", lineHeight: 1.6 }} />
                  )}
                </div>
              ))}

              <div style={{ display: "flex", gap: 10, marginTop: 4 }}>
                {step > 1 && <button onClick={() => setStep(s => s - 1)} style={{ padding: "10px 18px", borderRadius: 10, border: `1.5px solid ${BORDER}`, background: "transparent", color: MUTED, cursor: "pointer", fontSize: "0.85rem" }}>← Atrás</button>}
                <button onClick={step === total ? handleFinalSubmit : handleNext} className="nxt" style={{ flex: 1, padding: "12px", borderRadius: 10, border: "none", background: `linear-gradient(135deg,${GREEN},#7fff00)`, color: DARK, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1rem", fontWeight: 700, cursor: "pointer", transition: "all 0.2s", letterSpacing: "0.08em" }}>
                  {step === total ? "ENVIAR ✓" : "SIGUIENTE →"}
                </button>
              </div>
            </div>
          )}

          {/* DONE */}
          {isDone && (
            <div style={{ textAlign: "center", padding: "10px 0" }}>
              <div style={{ fontSize: "3.5rem", marginBottom: 16 }}>🎉</div>
              <h2 style={{ color: "#fff", fontFamily: "'Barlow Condensed',sans-serif", fontSize: "2.2rem", letterSpacing: "0.05em", marginBottom: 10, lineHeight: 1.1 }}>
                ¡GRACIAS POR TU<br /><span style={{ color: GREEN }}>FEEDBACK!</span>
              </h2>
              <p style={{ color: MUTED, fontSize: "0.88rem", lineHeight: 1.7 }}>Tu opinión contribuye a hacer de PADFIT el mejor complejo deportivo de Loja. ¡Nos vemos en las canchas! 🏓</p>
              <button onClick={onHome} style={{ marginTop: 20, padding: "10px 24px", borderRadius: 10, border: `1px solid rgba(57,255,20,0.3)`, background: "transparent", color: GREEN, cursor: "pointer", fontSize: "0.85rem" }}>
                ← Volver al inicio
              </button>
            </div>
          )}
        </div>
      </div>
      <p style={{ color: "#1c1c1c", fontSize: "0.6rem", marginTop: 16, fontFamily: "monospace", letterSpacing: "0.1em" }}>PADFIT © 2025 · LOJA, ECUADOR</p>
    </div>
  );
}

// ─── ADMIN LOGIN ──────────────────────────────────────────────────────────────
function AdminLogin({ onLogin, onHome }) {
  const [pass, setPass] = useState("");
  const [error, setError] = useState(false);
  const [shake, setShake] = useState(false);

  const handleLogin = () => {
    if (pass === ADMIN_PASSWORD) {
      onLogin();
    } else {
      setError(true);
      setShake(true);
      setTimeout(() => setShake(false), 500);
      setPass("");
    }
  };

  return (
    <div style={{ minHeight: "100vh", background: DARK, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 24, fontFamily: "'DM Sans',sans-serif" }}>
      <style>{globalCSS}</style>
      <img src={LOGO_B64} alt="PADFIT" style={{ height: 50, objectFit: "contain", marginBottom: 28, cursor: "pointer", filter: "drop-shadow(0 0 10px rgba(57,255,20,0.35))" }} onClick={onHome} />

      <div className={shake ? "shake" : ""} style={{ width: "100%", maxWidth: 360, background: CARD, borderRadius: 18, border: `1px solid ${BORDER}`, padding: "28px 24px", textAlign: "center", boxShadow: "0 20px 60px rgba(0,0,0,0.6)" }}>
        <div style={{ fontSize: "2rem", marginBottom: 12 }}>🔐</div>
        <h2 style={{ color: "#fff", fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1.5rem", letterSpacing: "0.08em", marginBottom: 6 }}>PANEL ADMINISTRATIVO</h2>
        <p style={{ color: MUTED, fontSize: "0.82rem", marginBottom: 20 }}>Ingresa tu contraseña para acceder</p>

        <input
          type="password"
          value={pass}
          onChange={e => { setPass(e.target.value); setError(false); }}
          onKeyDown={e => e.key === "Enter" && handleLogin()}
          placeholder="Contraseña"
          style={{ width: "100%", padding: "12px 16px", background: "#0e0e0e", border: `1.5px solid ${error ? "#e74c3c" : BORDER}`, borderRadius: 10, color: TEXT, fontSize: "1rem", fontFamily: "'DM Sans',sans-serif", letterSpacing: "0.1em", textAlign: "center", transition: "border-color 0.2s" }}
        />
        {error && <p style={{ color: "#e74c3c", fontSize: "0.78rem", marginTop: 8 }}>Contraseña incorrecta</p>}

        <button onClick={handleLogin} style={{ marginTop: 16, width: "100%", padding: "13px", borderRadius: 10, border: "none", background: `linear-gradient(135deg,${GREEN},#7fff00)`, color: DARK, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1rem", fontWeight: 700, cursor: "pointer", letterSpacing: "0.08em", transition: "all 0.2s" }}>
          ACCEDER →
        </button>
      </div>
    </div>
  );
}

// ─── DASHBOARD ────────────────────────────────────────────────────────────────
function Dashboard({ responses, sections, onEditSections, onClearData, onLogout, onHome }) {
  const [aiReport, setAiReport] = useState(null);
  const [aiLoading, setAiLoading] = useState(false);
  const [tab, setTab] = useState("overview");

  const total = responses.length;

  const getAvg = (secId, qid) => {
    const vals = responses.map(r => r[`${secId}_${qid}`]).filter(v => typeof v === "number" && v > 0);
    if (!vals.length) return null;
    return (vals.reduce((a, b) => a + b, 0) / vals.length).toFixed(1);
  };

  const getNPS = () => {
    const vals = responses.map(r => r["general_q1"]).filter(v => typeof v === "number");
    if (!vals.length) return null;
    const p = vals.filter(v => v >= 9).length;
    const d = vals.filter(v => v <= 6).length;
    return Math.round(((p - d) / vals.length) * 100);
  };

  const getTopOption = (secId, qid) => {
    const vals = responses.map(r => r[`${secId}_${qid}`]).filter(Boolean).flat();
    if (!vals.length) return null;
    const cnt = {};
    vals.forEach(v => { cnt[v] = (cnt[v] || 0) + 1; });
    return Object.entries(cnt).sort((a, b) => b[1] - a[1])[0];
  };

  const runAI = async () => {
    setAiLoading(true);
    const summary = sections.map(s => {
      const rQ = s.questions.find(q => q.type === "rating");
      const avg = rQ ? getAvg(s.id, rQ.id) : null;
      const comments = responses.map(r => r[`${s.id}_q3`]).filter(Boolean).slice(0, 6);
      return `${s.label}: rating=${avg || "sin datos"}/5 | comentarios: ${comments.length ? comments.join(" | ") : "ninguno"}`;
    }).join("\n");
    const nps = getNPS();

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1200,
          system: `Eres el analista de calidad y experiencia del cliente de PADFIT, complejo deportivo premium en Loja, Ecuador (pádel, squash, CrossFit, fisioterapia, nutrición, rooftop bar).
Analiza los datos como consultor senior. Responde SOLO en JSON válido sin backticks ni texto extra:
{"estado_general":"1 frase del estado actual","score_global":"X.X/5","fortalezas":["fortaleza 1","fortaleza 2","fortaleza 3"],"alertas":["alerta 1 con dato","alerta 2 con dato"],"plan_accion":[{"prioridad":1,"area":"nombre","problema":"qué está pasando","accion":"qué hacer exactamente","impacto":"alto|medio|bajo"},{"prioridad":2,"area":"nombre","problema":"qué está pasando","accion":"qué hacer exactamente","impacto":"alto|medio|bajo"},{"prioridad":3,"area":"nombre","problema":"qué está pasando","accion":"qué hacer exactamente","impacto":"alto|medio|bajo"}],"insight_clave":"El insight más valioso en 1 frase","mensaje_equipo":"Frase motivadora basada en los datos"}`,
          messages: [{ role: "user", content: `Encuestas: ${total}\nNPS: ${nps !== null ? nps : "sin datos"}\n\nResultados:\n${summary}` }]
        })
      });
      const data = await res.json();
      const raw = data.content?.map(i => i.text || "").join("") || "";
      const clean = raw.replace(/```json|```/g, "").trim();
      setAiReport(JSON.parse(clean));
    } catch {
      setAiReport({
        estado_general: "Datos procesados. Se necesitan más respuestas para un análisis profundo.",
        score_global: "—",
        fortalezas: ["Clientes activos respondiendo", "Diversidad de servicios usados", "Feedback constructivo"],
        alertas: ["Muestra pequeña — recolectar más respuestas", "Revisar comentarios abiertos manualmente"],
        plan_accion: [{ prioridad: 1, area: "General", problema: "Muestra insuficiente", accion: "Compartir el enlace de encuesta activamente esta semana", impacto: "alto" }],
        insight_clave: "Con más respuestas la IA detectará patrones ocultos por área.",
        mensaje_equipo: "¡Cada respuesta cuenta — PADFIT escucha a su comunidad!"
      });
    }
    setAiLoading(false);
  };

  const nps = getNPS();
  const npsColor = nps === null ? MUTED : nps >= 50 ? GREEN : nps >= 0 ? "#F5A623" : "#e74c3c";

  const Tab = ({ id, label, icon }) => (
    <button onClick={() => setTab(id)} style={{ padding: "8px 14px", borderRadius: "8px 8px 0 0", border: "none", cursor: "pointer", background: tab === id ? "rgba(57,255,20,0.1)" : "transparent", color: tab === id ? GREEN : MUTED, fontSize: "0.78rem", fontFamily: "'DM Sans',sans-serif", fontWeight: 600, borderBottom: tab === id ? `2px solid ${GREEN}` : "2px solid transparent", transition: "all 0.15s", whiteSpace: "nowrap" }}>
      {icon} {label}
    </button>
  );

  return (
    <div style={{ minHeight: "100vh", background: DARK, fontFamily: "'DM Sans',sans-serif", padding: "16px", maxWidth: 680, margin: "0 auto" }}>
      <style>{globalCSS + `.card{background:${CARD};border:1px solid ${BORDER};border-radius:14px;padding:16px}`}</style>

      {/* Header */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 20, flexWrap: "wrap", gap: 10 }}>
        <img src={LOGO_B64} alt="PADFIT" style={{ height: 36, objectFit: "contain", cursor: "pointer", filter: "drop-shadow(0 0 8px rgba(57,255,20,0.3))" }} onClick={onHome} />
        <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
          <button onClick={onEditSections} style={{ padding: "7px 12px", borderRadius: 8, border: `1px solid ${BORDER}`, background: "transparent", color: MUTED, fontSize: "0.74rem", cursor: "pointer" }}>✏️ Editar preguntas</button>
          <button onClick={onClearData} style={{ padding: "7px 12px", borderRadius: 8, border: "1px solid #2a1a1a", background: "transparent", color: "#555", fontSize: "0.74rem", cursor: "pointer" }}>🗑️ Limpiar datos</button>
          <button onClick={onLogout} style={{ padding: "7px 12px", borderRadius: 8, border: `1px solid ${BORDER}`, background: "transparent", color: MUTED, fontSize: "0.74rem", cursor: "pointer" }}>🔒 Salir</button>
        </div>
      </div>

      {/* KPIs */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 10, marginBottom: 16 }}>
        <div className="card" style={{ textAlign: "center" }}>
          <div style={{ color: GREEN, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "2.2rem", fontWeight: 700, lineHeight: 1 }}>{total}</div>
          <div style={{ color: MUTED, fontSize: "0.68rem", marginTop: 4 }}>Respuestas</div>
        </div>
        <div className="card" style={{ textAlign: "center" }}>
          <div style={{ color: npsColor, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "2.2rem", fontWeight: 700, lineHeight: 1 }}>{nps !== null ? nps : "—"}</div>
          <div style={{ color: MUTED, fontSize: "0.68rem", marginTop: 4 }}>NPS Score</div>
        </div>
        <div className="card" style={{ textAlign: "center" }}>
          <div style={{ color: "#F5A623", fontFamily: "'Barlow Condensed',sans-serif", fontSize: "2.2rem", fontWeight: 700, lineHeight: 1 }}>{sections.length}</div>
          <div style={{ color: MUTED, fontSize: "0.68rem", marginTop: 4 }}>Áreas activas</div>
        </div>
      </div>

      {/* Tabs */}
      <div style={{ display: "flex", gap: 2, marginBottom: 14, borderBottom: `1px solid ${BORDER}`, overflowX: "auto" }}>
        <Tab id="overview" label="Resumen" icon="📊" />
        <Tab id="detail" label="Por sección" icon="🔍" />
        <Tab id="comments" label="Comentarios" icon="💬" />
        <Tab id="ai" label="Análisis IA" icon="🤖" />
      </div>

      {/* OVERVIEW */}
      {tab === "overview" && (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))", gap: 10 }}>
          {sections.map(s => {
            const rQ = s.questions.find(q => q.type === "rating");
            const avg = rQ ? getAvg(s.id, rQ.id) : null;
            const pct = avg ? (parseFloat(avg) / 5) * 100 : 0;
            const col = pct >= 80 ? GREEN : pct >= 60 ? "#F5A623" : "#e74c3c";
            return (
              <div key={s.id} className="card">
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
                  <span style={{ fontSize: "1.3rem" }}>{s.icon}</span>
                  <span style={{ color: TEXT, fontWeight: 600, fontSize: "0.85rem" }}>{s.label}</span>
                </div>
                {avg ? <>
                  <div style={{ color: col, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "2rem", fontWeight: 700, marginBottom: 4 }}>{avg}<span style={{ color: MUTED, fontSize: "0.9rem" }}>/5</span></div>
                  <div style={{ height: 3, background: "#1a1a1a", borderRadius: 2 }}>
                    <div style={{ height: "100%", width: `${pct}%`, background: col, borderRadius: 2 }} />
                  </div>
                </> : <div style={{ color: MUTED, fontSize: "0.78rem" }}>Sin datos aún</div>}
              </div>
            );
          })}
        </div>
      )}

      {/* DETAIL */}
      {tab === "detail" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {sections.map(s => (
            <div key={s.id} className="card">
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}>
                <span style={{ fontSize: "1.3rem" }}>{s.icon}</span>
                <span style={{ color: GREEN, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1rem", fontWeight: 700, letterSpacing: "0.05em" }}>{s.label.toUpperCase()}</span>
              </div>
              {s.questions.filter(q => q.type !== "open").map(q => {
                if (q.type === "rating") {
                  const avg = getAvg(s.id, q.id);
                  return <div key={q.id} style={{ marginBottom: 12 }}>
                    <div style={{ color: MUTED, fontSize: "0.76rem", marginBottom: 4 }}>{q.text}</div>
                    {avg ? <><Stars value={Math.round(parseFloat(avg))} readonly /><div style={{ textAlign: "center", color: TEXT, fontSize: "0.78rem", fontFamily: "monospace" }}>{avg}/5</div></> : <span style={{ color: MUTED, fontSize: "0.74rem" }}>Sin datos</span>}
                  </div>;
                }
                if (q.type === "nps") {
                  const n = getNPS();
                  return <div key={q.id} style={{ marginBottom: 12 }}>
                    <div style={{ color: MUTED, fontSize: "0.76rem", marginBottom: 4 }}>{q.text}</div>
                    <div style={{ color: n === null ? MUTED : n >= 50 ? GREEN : n >= 0 ? "#F5A623" : "#e74c3c", fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1.6rem", fontWeight: 700 }}>
                      {n !== null ? `NPS: ${n}` : "Sin datos"}
                    </div>
                  </div>;
                }
                if (q.type === "single" || q.type === "multi") {
                  const top = getTopOption(s.id, q.id);
                  return <div key={q.id} style={{ marginBottom: 12 }}>
                    <div style={{ color: MUTED, fontSize: "0.76rem", marginBottom: 4 }}>{q.text}</div>
                    {top ? <div style={{ padding: "6px 12px", borderRadius: 6, background: "rgba(57,255,20,0.07)", border: "1px solid rgba(57,255,20,0.15)", display: "inline-block" }}>
                      <span style={{ color: GREEN, fontSize: "0.8rem" }}>🏆 {top[0]}</span>
                      <span style={{ color: MUTED, fontSize: "0.7rem", marginLeft: 8 }}>({top[1]} resp.)</span>
                    </div> : <span style={{ color: MUTED, fontSize: "0.74rem" }}>Sin datos</span>}
                  </div>;
                }
                return null;
              })}
            </div>
          ))}
        </div>
      )}

      {/* COMMENTS */}
      {tab === "comments" && (
        <div>
          {sections.map(s => {
            const openQ = s.questions.find(q => q.type === "open");
            if (!openQ) return null;
            const comments = responses.map(r => r[`${s.id}_${openQ.id}`]).filter(Boolean);
            if (!comments.length) return null;
            return (
              <div key={s.id} className="card" style={{ marginBottom: 10 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
                  <span>{s.icon}</span>
                  <span style={{ color: GREEN, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "0.95rem", fontWeight: 700 }}>{s.label.toUpperCase()}</span>
                  <span style={{ color: MUTED, fontSize: "0.7rem", fontFamily: "monospace" }}>({comments.length})</span>
                </div>
                {comments.map((c, i) => (
                  <div key={i} style={{ padding: "8px 12px", borderRadius: 8, background: "#0e0e0e", border: `1px solid ${BORDER}`, marginBottom: 6, color: TEXT, fontSize: "0.82rem", lineHeight: 1.5 }}>
                    <span style={{ color: GREEN, fontFamily: "monospace", marginRight: 8, fontSize: "0.68rem" }}>#{i + 1}</span>{c}
                  </div>
                ))}
              </div>
            );
          })}
          {sections.every(s => {
            const oq = s.questions.find(q => q.type === "open");
            return !oq || !responses.map(r => r[`${s.id}_${oq.id}`]).filter(Boolean).length;
          }) && <div style={{ textAlign: "center", color: MUTED, padding: 40 }}>Sin comentarios aún</div>}
        </div>
      )}

      {/* AI ANALYSIS */}
      {tab === "ai" && (
        <div>
          {!aiReport && (
            <div style={{ textAlign: "center", padding: "20px 0" }}>
              <div style={{ color: MUTED, fontSize: "0.85rem", marginBottom: 20, lineHeight: 1.7 }}>
                Analiza las <strong style={{ color: TEXT }}>{total}</strong> respuestas con IA y recibe un reporte ejecutivo con prioridades de acción concretas.
              </div>
              <button onClick={runAI} disabled={aiLoading || total === 0} style={{ padding: "13px 28px", borderRadius: 12, border: "none", background: total === 0 ? "#1a1a1a" : `linear-gradient(135deg,${GREEN},#7fff00)`, color: total === 0 ? MUTED : DARK, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1rem", fontWeight: 700, cursor: total === 0 || aiLoading ? "not-allowed" : "pointer", letterSpacing: "0.08em", transition: "all 0.2s" }}>
                {aiLoading ? "⏳ ANALIZANDO..." : "🤖 GENERAR ANÁLISIS IA"}
              </button>
              {total === 0 && <div style={{ color: MUTED, fontSize: "0.74rem", marginTop: 10 }}>Necesitas al menos 1 respuesta</div>}
            </div>
          )}
          {aiReport && (
            <div>
              <div className="card" style={{ marginBottom: 10, borderColor: "rgba(57,255,20,0.25)", background: "rgba(57,255,20,0.03)" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 8 }}>
                  <div style={{ color: GREEN, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "0.85rem", letterSpacing: "0.1em" }}>📋 ESTADO GENERAL</div>
                  {aiReport.score_global && <div style={{ color: GREEN, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1.4rem", fontWeight: 700 }}>{aiReport.score_global}</div>}
                </div>
                <p style={{ color: TEXT, fontSize: "0.86rem", lineHeight: 1.7 }}>{aiReport.estado_general}</p>
              </div>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 10 }}>
                <div className="card">
                  <div style={{ color: GREEN, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "0.8rem", letterSpacing: "0.1em", marginBottom: 8 }}>✅ FORTALEZAS</div>
                  {aiReport.fortalezas?.map((f, i) => (
                    <div key={i} style={{ display: "flex", gap: 6, marginBottom: 6, alignItems: "flex-start" }}>
                      <span style={{ color: GREEN, fontWeight: 700, minWidth: 14, fontSize: "0.8rem" }}>+</span>
                      <span style={{ color: TEXT, fontSize: "0.78rem", lineHeight: 1.4 }}>{f}</span>
                    </div>
                  ))}
                </div>
                <div className="card">
                  <div style={{ color: "#e74c3c", fontFamily: "'Barlow Condensed',sans-serif", fontSize: "0.8rem", letterSpacing: "0.1em", marginBottom: 8 }}>⚠️ ALERTAS</div>
                  {aiReport.alertas?.map((a, i) => (
                    <div key={i} style={{ display: "flex", gap: 6, marginBottom: 6, alignItems: "flex-start" }}>
                      <span style={{ color: "#e74c3c", fontWeight: 700, minWidth: 14, fontSize: "0.8rem" }}>!</span>
                      <span style={{ color: TEXT, fontSize: "0.78rem", lineHeight: 1.4 }}>{a}</span>
                    </div>
                  ))}
                </div>
              </div>

              <div className="card" style={{ marginBottom: 10 }}>
                <div style={{ color: "#F5A623", fontFamily: "'Barlow Condensed',sans-serif", fontSize: "0.85rem", letterSpacing: "0.1em", marginBottom: 10 }}>🚀 PLAN DE ACCIÓN PRIORITARIO</div>
                {aiReport.plan_accion?.map((p, i) => (
                  <div key={i} style={{ padding: "10px 12px", borderRadius: 8, background: "#0e0e0e", border: `1px solid ${BORDER}`, marginBottom: 8 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                        <span style={{ color: DARK, background: GREEN, fontFamily: "monospace", fontSize: "0.68rem", fontWeight: 700, width: 20, height: 20, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center" }}>{p.prioridad}</span>
                        <span style={{ color: GREEN, fontSize: "0.82rem", fontWeight: 600 }}>{p.area}</span>
                      </div>
                      <span style={{ padding: "2px 8px", borderRadius: 10, background: p.impacto === "alto" ? "rgba(231,76,60,0.2)" : p.impacto === "medio" ? "rgba(245,166,35,0.2)" : "rgba(57,255,20,0.1)", color: p.impacto === "alto" ? "#e74c3c" : p.impacto === "medio" ? "#F5A623" : GREEN, fontSize: "0.62rem", fontFamily: "monospace", textTransform: "uppercase" }}>{p.impacto}</span>
                    </div>
                    <div style={{ color: "#888", fontSize: "0.75rem", marginBottom: 4 }}>{p.problema}</div>
                    <div style={{ color: TEXT, fontSize: "0.8rem", lineHeight: 1.4 }}><span style={{ color: "#F5A623" }}>→ </span>{p.accion}</div>
                  </div>
                ))}
              </div>

              {aiReport.insight_clave && (
                <div className="card" style={{ marginBottom: 10, borderColor: "rgba(245,166,35,0.2)", background: "rgba(245,166,35,0.03)" }}>
                  <div style={{ color: "#F5A623", fontFamily: "'Barlow Condensed',sans-serif", fontSize: "0.8rem", letterSpacing: "0.1em", marginBottom: 6 }}>💡 INSIGHT CLAVE</div>
                  <p style={{ color: TEXT, fontSize: "0.85rem", lineHeight: 1.6 }}>{aiReport.insight_clave}</p>
                </div>
              )}

              {aiReport.mensaje_equipo && (
                <div className="card" style={{ borderColor: "rgba(57,255,20,0.2)", background: "rgba(57,255,20,0.03)", textAlign: "center" }}>
                  <div style={{ color: GREEN, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "0.8rem", letterSpacing: "0.1em", marginBottom: 6 }}>💪 PARA EL EQUIPO PADFIT</div>
                  <p style={{ color: TEXT, fontSize: "0.86rem", lineHeight: 1.6, fontStyle: "italic" }}>"{aiReport.mensaje_equipo}"</p>
                </div>
              )}

              <button onClick={() => setAiReport(null)} style={{ marginTop: 12, width: "100%", padding: "10px", borderRadius: 10, border: `1px solid ${BORDER}`, background: "transparent", color: MUTED, cursor: "pointer", fontSize: "0.78rem" }}>
                🔄 Regenerar análisis
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ─── SECTION EDITOR ───────────────────────────────────────────────────────────
function SectionEditor({ sections, onSave, onBack }) {
  const [local, setLocal] = useState(JSON.parse(JSON.stringify(sections)));
  const Q_TYPES = ["rating", "single", "multi", "nps", "open"];

  const addSection = () => setLocal(s => [...s, { id: uid(), icon: "📝", label: "Nueva sección", questions: [{ id: "q1", type: "rating", text: "Nueva pregunta", options: [] }] }]);
  const removeSection = (si) => setLocal(s => s.filter((_, i) => i !== si));
  const updSec = (si, f, v) => setLocal(s => s.map((sec, i) => i === si ? { ...sec, [f]: v } : sec));
  const addQ = (si) => setLocal(s => s.map((sec, i) => i === si ? { ...sec, questions: [...sec.questions, { id: uid(), type: "rating", text: "Nueva pregunta", options: [] }] } : sec));
  const removeQ = (si, qi) => setLocal(s => s.map((sec, i) => i === si ? { ...sec, questions: sec.questions.filter((_, j) => j !== qi) } : sec));
  const updQ = (si, qi, f, v) => setLocal(s => s.map((sec, i) => i === si ? { ...sec, questions: sec.questions.map((q, j) => j === qi ? { ...q, [f]: v } : q) } : sec));

  return (
    <div style={{ minHeight: "100vh", background: DARK, fontFamily: "'DM Sans',sans-serif", padding: 16, maxWidth: 680, margin: "0 auto" }}>
      <style>{globalCSS}</style>
      <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 18 }}>
        <button onClick={onBack} style={{ padding: "6px 12px", borderRadius: 8, border: `1px solid ${BORDER}`, background: "transparent", color: MUTED, cursor: "pointer", fontSize: "0.8rem" }}>← Volver</button>
        <h2 style={{ color: GREEN, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1.3rem", letterSpacing: "0.08em" }}>EDITOR DE PREGUNTAS</h2>
      </div>

      {local.map((sec, si) => (
        <div key={sec.id} style={{ background: CARD, border: `1px solid ${BORDER}`, borderRadius: 14, padding: 14, marginBottom: 10 }}>
          <div style={{ display: "flex", gap: 8, marginBottom: 10, alignItems: "center" }}>
            <input value={sec.icon} onChange={e => updSec(si, "icon", e.target.value)}
              style={{ width: 42, padding: 6, background: "#0e0e0e", border: `1px solid ${BORDER}`, borderRadius: 6, color: TEXT, fontSize: "1.2rem", textAlign: "center" }} />
            <input value={sec.label} onChange={e => updSec(si, "label", e.target.value)}
              style={{ flex: 1, padding: "8px 12px", background: "#0e0e0e", border: `1px solid ${BORDER}`, borderRadius: 8, color: TEXT, fontSize: "0.88rem", fontFamily: "'DM Sans',sans-serif" }} />
            <button onClick={() => removeSection(si)} style={{ padding: "6px 10px", borderRadius: 6, border: "1px solid #2a1a1a", background: "transparent", color: "#555", cursor: "pointer", fontSize: "0.78rem" }}>✕</button>
          </div>

          {sec.questions.map((q, qi) => (
            <div key={q.id} style={{ padding: 10, background: "#0e0e0e", borderRadius: 8, border: `1px solid ${BORDER}`, marginBottom: 8 }}>
              <div style={{ display: "flex", gap: 8, marginBottom: 8 }}>
                <select value={q.type} onChange={e => updQ(si, qi, "type", e.target.value)}
                  style={{ padding: "6px 8px", background: "#1a1a1a", border: `1px solid ${BORDER}`, borderRadius: 6, color: TEXT, fontSize: "0.76rem", cursor: "pointer" }}>
                  {Q_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
                <input value={q.text} onChange={e => updQ(si, qi, "text", e.target.value)}
                  style={{ flex: 1, padding: "6px 10px", background: "#1a1a1a", border: `1px solid ${BORDER}`, borderRadius: 6, color: TEXT, fontSize: "0.8rem", fontFamily: "'DM Sans',sans-serif" }} />
                <button onClick={() => removeQ(si, qi)} style={{ padding: "5px 8px", borderRadius: 6, border: "1px solid #2a1a1a", background: "transparent", color: "#555", cursor: "pointer", fontSize: "0.72rem" }}>✕</button>
              </div>
              {(q.type === "single" || q.type === "multi") && (
                <div>
                  <div style={{ color: MUTED, fontSize: "0.7rem", marginBottom: 4 }}>Opciones (una por línea):</div>
                  <textarea
                    value={(q.options || []).join("\n")}
                    onChange={e => updQ(si, qi, "options", e.target.value.split("\n").filter(Boolean))}
                    style={{ width: "100%", minHeight: 65, padding: "8px", background: "#111", border: `1px solid ${BORDER}`, borderRadius: 6, color: TEXT, fontSize: "0.78rem", fontFamily: "'DM Sans',sans-serif", resize: "vertical" }} />
                </div>
              )}
            </div>
          ))}

          <button onClick={() => addQ(si)} style={{ width: "100%", padding: 8, borderRadius: 8, border: `1px dashed ${BORDER}`, background: "transparent", color: MUTED, cursor: "pointer", fontSize: "0.78rem" }}>
            + Agregar pregunta
          </button>
        </div>
      ))}

      <button onClick={addSection} style={{ width: "100%", padding: 10, borderRadius: 10, border: "1px dashed rgba(57,255,20,0.3)", background: "transparent", color: GREEN, cursor: "pointer", fontSize: "0.82rem", marginBottom: 10 }}>
        + Agregar sección
      </button>
      <button onClick={() => onSave(local)} style={{ width: "100%", padding: "13px", borderRadius: 12, border: "none", background: `linear-gradient(135deg,${GREEN},#7fff00)`, color: DARK, fontFamily: "'Barlow Condensed',sans-serif", fontSize: "1rem", fontWeight: 700, cursor: "pointer", letterSpacing: "0.08em" }}>
        GUARDAR CAMBIOS ✓
      </button>
    </div>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [view, setView] = useState("home");          // home | survey | login | dashboard | editor
  const [adminAuth, setAdminAuth] = useState(false);
  const [sections, setSections] = useState(DEFAULT_SECTIONS);
  const [responses, setResponses] = useState([]);
  const [loaded, setLoaded] = useState(false);

  // ── Supabase config ──────────────────────────────────────────────
  const SUPA_URL = "https://iptpgewmjkieqizgkesd.supabase.co";
  const SUPA_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImlwdHBnZXdtamtpZXFpemdrZXNkIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzk0NzU4MzksImV4cCI6MjA5NTA1MTgzOX0.2Zfqfy8evyrAiRgWkrJHAvj6KeBVp04VuNIalScauVo";

  const supa = async (path, opts = {}) => {
    const res = await fetch(`${SUPA_URL}/rest/v1/${path}`, {
      headers: {
        "apikey": SUPA_KEY,
        "Authorization": `Bearer ${SUPA_KEY}`,
        "Content-Type": "application/json",
        "Prefer": opts.prefer || "",
        ...opts.headers
      },
      ...opts
    });
    if (!res.ok) throw new Error(await res.text());
    const text = await res.text();
    return text ? JSON.parse(text) : null;
  };

  // Load from Supabase on mount
  useEffect(() => {
    const load = async () => {
      try {
        // Load sections config
        const secRows = await supa("sections?id=eq.config&select=data");
        if (secRows && secRows.length > 0) setSections(secRows[0].data);
      } catch { /* use defaults */ }
      try {
        // Load all responses
        const respRows = await supa("responses?select=id,ts,data&order=ts.desc");
        if (respRows) setResponses(respRows.map(r => ({ id: r.id, ts: r.ts, ...r.data })));
      } catch { /* use empty */ }
      setLoaded(true);
    };
    load();
  }, []);

  const saveSections = async (arr) => {
    setSections(arr);
    try {
      await supa("sections", {
        method: "POST",
        prefer: "resolution=merge-duplicates",
        headers: { "Prefer": "resolution=merge-duplicates" },
        body: JSON.stringify({ id: "config", data: arr, updated_at: new Date().toISOString() })
      });
    } catch (e) { console.error("Error saving sections:", e); }
  };

  const saveResponses = async (arr) => {
    setResponses(arr);
    // NOTE: individual responses are inserted one by one in handleSubmit
  };

  const handleSubmit = async (ans) => {
    try {
      const newRow = await supa("responses", {
        method: "POST",
        headers: { "Prefer": "return=representation" },
        body: JSON.stringify({ data: ans })
      });
      const row = Array.isArray(newRow) ? newRow[0] : newRow;
      setResponses(prev => [{ id: row.id, ts: row.ts, ...ans }, ...prev]);
    } catch (e) {
      console.error("Error saving response:", e);
      // Fallback: add locally so user sees confirmation
      setResponses(prev => [{ id: uid(), ts: new Date().toISOString(), ...ans }, ...prev]);
    }
  };

  const handleSaveSections = async (sec) => {
    await saveSections(sec);
    setView("dashboard");
  };

  const handleClear = async () => {
    if (window.confirm("¿Eliminar TODAS las respuestas? Esta acción no se puede deshacer.")) {
      try {
        await supa("responses?id=neq.00000000-0000-0000-0000-000000000000", {
          method: "DELETE"
        });
        setResponses([]);
      } catch (e) { console.error("Error clearing:", e); }
    }
  };

  if (!loaded) {
    return (
      <div style={{ minHeight: "100vh", background: DARK, display: "flex", alignItems: "center", justifyContent: "center" }}>
        <div style={{ color: GREEN, fontFamily: "monospace", fontSize: "0.88rem" }}>Cargando PADFIT…</div>
      </div>
    );
  }

  if (view === "home") return <HomeScreen onSurvey={() => setView("survey")} onAdmin={() => setView("login")} />;

  if (view === "survey") return <SurveyView sections={sections} onSubmit={handleSubmit} onHome={() => setView("home")} />;

  if (view === "login") return (
    <AdminLogin
      onHome={() => setView("home")}
      onLogin={() => { setAdminAuth(true); setView("dashboard"); }}
    />
  );

  if (view === "dashboard" && adminAuth) return (
    <Dashboard
      responses={responses}
      sections={sections}
      onEditSections={() => setView("editor")}
      onClearData={handleClear}
      onHome={() => setView("home")}
      onLogout={() => { setAdminAuth(false); setView("home"); }}
    />
  );

  if (view === "editor" && adminAuth) return (
    <SectionEditor
      sections={sections}
      onSave={handleSaveSections}
      onBack={() => setView("dashboard")}
    />
  );

  // Fallback — shouldn't happen
  return <HomeScreen onSurvey={() => setView("survey")} onAdmin={() => setView("login")} />;
}
